const resp=$input.first().json;const ctx=$('Extract Fields').first().json;
let payload;
try{payload=JSON.parse(resp.choices?.[0]?.message?.content||'{}');}catch(e){payload={expenses:[],summary:'No pude leer el PDF.'};}
const expenses=Array.isArray(payload.expenses)?payload.expenses:[];
const total=expenses.reduce((s,e)=>s+Number(e.amount||0),0);
const fmt=n=>Number(n||0).toLocaleString('es-AR');
let preview='';
if(expenses.length){
  preview='\n\nPrimeros movimientos:\n'+expenses.slice(0,5).map(e=>`• $${fmt(e.amount)} ${e.category_hint||''} ${e.description||e.merchant||''} ${e.transaction_date_iso||''}`).join('\n');
  if(expenses.length>5) preview+=`\n... y ${expenses.length-5} más.`;
}
// synthesize text for the rest of the flow
const syntheticText=`__pdf_import__${expenses.length}`;
return [{ json:{ text:syntheticText, phone:ctx.phone, remoteJid:ctx.remoteJid, instance:ctx.instance, messageId:ctx.messageId, pushName:ctx.pushName, pdf_data:{expenses, summary:payload.summary||'', total, preview} }}];

const buf=$input.first().json.bufferedMessages||[];
const ctx=$('Merge Ctx').first().json;
const combined=buf.filter(Boolean).map(s=>String(s).trim()).join(' \n ').trim();
// detect PDF import
const pdfMarker=combined.match(/__pdf_import__(\d+)/);
const isPdfImport=!!pdfMarker;
let pdfData=null;
if(isPdfImport){ try{ pdfData=$('Parse PDF Result').first().json.pdf_data; }catch(e){} }
return [{ json:{ userId:ctx.userId, phone:ctx.phone, remoteJid:ctx.remoteJid, instance:ctx.instance, messageId:ctx.messageId, pushName:ctx.pushName, combinedText:combined, bufferLength:buf.length, convState:ctx.convState, convContext:ctx.convContext, onboarded:ctx.onboarded, isPdfImport, pdfData }}];

