let raw=$input.first().json;
let payload=raw.message?.content||raw.content||raw;
if(typeof payload==='string'){try{payload=JSON.parse(payload);}catch(e){payload={intent:'unknown',human_reply:'No te entendí, ¿podés repetirlo?'};}}
const ctx=$('Concat').first().json;
return [{ json:{ ...ctx, intent:payload.intent||'unknown', human_reply:payload.human_reply||'', needs_clarification:!!payload.needs_clarification, transaction:payload.transaction||{}, query:payload.query||{}, chart:payload.chart||{}, group:payload.group||{}, budget:payload.budget||{}, category_action:payload.category_action||{}, recurring:payload.recurring||{}, report:payload.report||{}, match:payload.match||{}, raw_ai:payload }}];

const ctx=$input.first().json;
const q=ctx.query||{};
const period=q.period||'this_month';
const periodSql={today:"transaction_date = CURRENT_DATE",yesterday:"transaction_date = CURRENT_DATE - INTERVAL '1 day'",this_week:"transaction_date >= DATE_TRUNC('week', CURRENT_DATE)",this_month:"transaction_date >= DATE_TRUNC('month', CURRENT_DATE)",last_month:"transaction_date >= DATE_TRUNC('month', CURRENT_DATE - INTERVAL '1 month') AND transaction_date < DATE_TRUNC('month', CURRENT_DATE)",this_year:"transaction_date >= DATE_TRUNC('year', CURRENT_DATE)",all:"TRUE"}[period]||"transaction_date >= DATE_TRUNC('month', CURRENT_DATE)";
let sql,params;const userId=ctx.userId;const catHint=(q.category_hint||'').trim();const descHint=(q.description_hint||'').trim();
if(q.kind==='find'){const hint=descHint||catHint||'';if(!hint){sql=`SELECT t.transaction_date::text AS d, t.amount, t.description, c.name AS cat, c.emoji FROM v_reportable_transactions t LEFT JOIN categories c ON c.id=t.category_id WHERE t.user_id=$1 AND ${periodSql} ORDER BY t.transaction_date DESC, t.created_at DESC LIMIT 15`;params=[userId];}else{sql=`SELECT t.transaction_date::text AS d, t.amount, t.description, c.name AS cat, c.emoji FROM v_reportable_transactions t LEFT JOIN categories c ON c.id=t.category_id WHERE t.user_id=$1 AND ${periodSql} AND (normalize_text(COALESCE(t.description,'')) % normalize_text($2) OR normalize_text(COALESCE(c.name,'')) % normalize_text($2)) ORDER BY t.transaction_date DESC, t.created_at DESC LIMIT 15`;params=[userId,hint];}}
else if(q.kind==='list_recent'){const descFilter=descHint?" AND normalize_text(COALESCE(t.description,'')) % normalize_text($2)":'';sql=`SELECT t.transaction_date::text AS d, t.amount, t.description, c.name AS cat, c.emoji FROM v_reportable_transactions t LEFT JOIN categories c ON c.id=t.category_id WHERE t.user_id=$1 AND t.type='expense' AND ${periodSql}${descFilter} ORDER BY t.transaction_date DESC, t.created_at DESC LIMIT 10`;params=descHint?[userId,descHint]:[userId];}
else if(q.kind==='by_category'){sql=`SELECT c.name AS category, c.emoji, SUM(t.amount) AS total, COUNT(*) AS n FROM v_reportable_transactions t LEFT JOIN categories c ON c.id=t.category_id WHERE t.user_id=$1 AND t.type='expense' AND ${periodSql} GROUP BY c.name, c.emoji ORDER BY total DESC`;params=[userId];}
else if(q.kind==='average'){sql=`SELECT AVG(amount) AS avg_amount, COUNT(*) AS n FROM v_reportable_transactions WHERE user_id=$1 AND type='expense' AND ${periodSql}`;params=[userId];}
else{if(catHint){sql=`SELECT COALESCE(SUM(t.amount),0) AS total, COUNT(*) AS n, c.name AS category, c.emoji FROM v_reportable_transactions t JOIN categories c ON c.id=t.category_id WHERE t.user_id=$1 AND t.type='expense' AND ${periodSql} AND c.normalized_name % normalize_text($2) GROUP BY c.name, c.emoji ORDER BY total DESC LIMIT 5`;params=[userId,catHint];}else{sql=`SELECT COALESCE(SUM(amount),0) AS total, COUNT(*) AS n FROM v_reportable_transactions WHERE user_id=$1 AND type='expense' AND ${periodSql}`;params=[userId];}}
return [{json:{...ctx,sql,params,period}}];

const items=$input.all();const ctx=$('Parse AI').first().json;const meta=$('Build Query SQL').first().json;const period=meta.period;const kind=meta.query?.kind||'total';const descHint=(meta.query?.description_hint||'').trim();const fmt=n=>Number(n||0).toLocaleString('es-AR',{minimumFractionDigits:0,maximumFractionDigits:2});const periodLabel=({today:'hoy',yesterday:'ayer',this_week:'esta semana',this_month:'este mes',last_month:'el mes pasado',this_year:'este año',all:'en total'})[period]||period;
let text='';
const isEmpty=!items.length||(items.length===1&&!items[0].json.amount&&(items[0].json.total==='0'||items[0].json.total===0||items[0].json.total===null||items[0].json.total===undefined)&&items[0].json.d===undefined&&items[0].json.avg_amount===undefined);
if(isEmpty){
  if(kind==='find')text=`🔍 No encontré gastos${descHint?' que coincidan con "'+descHint+'"':''} ${periodLabel}.`;
  else text=`📭 No tengo registros para ${periodLabel} todavía.`;
}
else if(items[0].json.d!==undefined){
  const header=kind==='find'?(`🔍 Encontré ${items.length} ${items.length==1?'gasto':'gastos'}${descHint?' de "'+descHint+'"':''} ${periodLabel}:`):`🧾 Últimos movimientos ${periodLabel}:`;
  text=header+'\n'+items.map(i=>`${i.json.d} · ${i.json.emoji||''} ${i.json.cat||'—'} · $${fmt(i.json.amount)}${i.json.description?' — '+i.json.description:''}`).join('\n');
  if(kind==='find'){const total=items.reduce((s,i)=>s+Number(i.json.amount||0),0);text+=`\n\n*Total:* $${fmt(total)}`;}
}
else if(items[0].json.category!==undefined){text=`📊 Gastos por categoría ${periodLabel}:\n`+items.slice(0,10).map(i=>`${i.json.emoji||''} ${i.json.category||'—'}: $${fmt(i.json.total)} (${i.json.n})`).join('\n');const total=items.reduce((s,i)=>s+Number(i.json.total||0),0);text+=`\n\n*Total:* $${fmt(total)}`;}
else if(items[0].json.avg_amount!==undefined){const r=items[0].json;text=`📈 Promedio ${periodLabel}: $${fmt(r.avg_amount)} (${r.n} mov).`;}
else if(items[0].json.total!==undefined){const r=items[0].json;text=`💸 Gastaste $${fmt(r.total)} ${periodLabel} (${r.n} ${r.n==1?'movimiento':'movimientos'}).`;}
else{text='No tengo registros.';}
return [{json:{replyText:text,replyKind:'text',userId:ctx.userId,phone:ctx.phone,instance:ctx.instance,remoteJid:ctx.remoteJid,messageId:ctx.messageId,reactionEmoji:kind==='find'?'🔍':'📊'}}];

const ctx=$input.first().json;const c=ctx.chart||{};const period=c.period||'this_month';const periodSql={today:"transaction_date = CURRENT_DATE",yesterday:"transaction_date = CURRENT_DATE - INTERVAL '1 day'",this_week:"transaction_date >= DATE_TRUNC('week', CURRENT_DATE)",this_month:"transaction_date >= DATE_TRUNC('month', CURRENT_DATE)",last_month:"transaction_date >= DATE_TRUNC('month', CURRENT_DATE - INTERVAL '1 month') AND transaction_date < DATE_TRUNC('month', CURRENT_DATE)",this_year:"transaction_date >= DATE_TRUNC('year', CURRENT_DATE)"}[period]||"transaction_date >= DATE_TRUNC('month', CURRENT_DATE)";
let sql;
if(c.kind==='by_day'){sql=`SELECT transaction_date::text AS label, SUM(amount)::numeric AS value FROM v_reportable_transactions WHERE user_id=$1 AND type='expense' AND ${periodSql} GROUP BY transaction_date ORDER BY transaction_date`;}
else if(c.kind==='by_payment_method'){sql=`SELECT COALESCE(p.name,'Sin método') AS label, SUM(t.amount)::numeric AS value FROM v_reportable_transactions t LEFT JOIN payment_methods p ON p.id=t.payment_method_id WHERE t.user_id=$1 AND t.type='expense' AND ${periodSql} GROUP BY p.name ORDER BY value DESC`;}
else if(c.kind==='trend'){sql=`SELECT TO_CHAR(DATE_TRUNC('month', transaction_date),'YYYY-MM') AS label, SUM(amount)::numeric AS value FROM v_reportable_transactions WHERE user_id=$1 AND type='expense' AND transaction_date >= CURRENT_DATE - INTERVAL '6 months' GROUP BY 1 ORDER BY 1`;}
else{sql=`SELECT COALESCE(c.name,'Sin categoría') AS label, SUM(t.amount)::numeric AS value FROM v_reportable_transactions t LEFT JOIN categories c ON c.id=t.category_id WHERE t.user_id=$1 AND t.type='expense' AND ${periodSql} GROUP BY c.name ORDER BY value DESC LIMIT 12`;}
return [{json:{...ctx,sql,kind:c.kind||'by_category',period}}];

const items=$input.all();const ctx=$('Parse AI').first().json;const meta=$('Build Chart SQL').first().json;const periodLabel=({today:'hoy',yesterday:'ayer',this_week:'esta semana',this_month:'este mes',last_month:'el mes pasado',this_year:'este año'})[meta.period]||meta.period;
if(!items.length||items.every(i=>!i.json.label)){return [{json:{replyKind:'text',replyText:`📭 No tengo gastos para ${periodLabel}. Mandame algunos primero.`,userId:ctx.userId,phone:ctx.phone,instance:ctx.instance,remoteJid:ctx.remoteJid,messageId:ctx.messageId,reactionEmoji:'📈'}}];}
const labels=items.map(i=>i.json.label);const values=items.map(i=>Number(i.json.value));const total=values.reduce((s,v)=>s+v,0);const isPie=meta.kind==='by_category'||meta.kind==='by_payment_method';const palette=['#FF6B6B','#4ECDC4','#FFD93D','#6BCB77','#4D96FF','#9D4EDD','#FF9F1C','#2EC4B6','#E71D36','#7209B7','#3A86FF','#FB5607'];const titleByKind=({by_category:'Gastos por categoría',by_payment_method:'Gastos por método de pago',by_day:'Gastos diarios',trend:'Tendencia mensual (6 meses)'})[meta.kind]||'Gastos';
let chart;
if(isPie){chart={type:'doughnut',data:{labels,datasets:[{data:values,backgroundColor:palette}]},options:{plugins:{title:{display:true,text:`${titleByKind} — ${periodLabel}`},legend:{position:'right'}}}};}
else{chart={type:'bar',data:{labels,datasets:[{label:'Gasto',data:values,backgroundColor:palette[0]}]},options:{plugins:{title:{display:true,text:`${titleByKind} — ${periodLabel}`},legend:{display:false}},scales:{y:{beginAtZero:true}}}};}
const url='https://quickchart.io/chart?bkg=white&w=900&h=600&c='+encodeURIComponent(JSON.stringify(chart));const fmt=n=>Number(n||0).toLocaleString('es-AR');const caption=`${titleByKind} — ${periodLabel}\nTotal: $${fmt(total)}`;
return [{json:{replyKind:'image',imageUrl:url,replyText:caption,userId:ctx.userId,phone:ctx.phone,instance:ctx.instance,remoteJid:ctx.remoteJid,messageId:ctx.messageId,reactionEmoji:'📈'}}];

const items=$input.all();const ctx=$('Parse AI').first().json;const fmt=n=>Number(n||0).toLocaleString('es-AR');
let text;
if(!items.length||!items[0].json.id){text='📭 No tenés grupos creados todavía. Probá: "creá un viaje a bariloche".';}
else{text='🧳 Tus grupos:\n'+items.map(i=>{const j=i.json;return `${j.excluded?'🚫 ':''}${j.emoji||'•'} *${j.name}* (${j.kind}) — ${j.n} gastos · $${fmt(j.total)}`;}).join('\n');}
return [{json:{replyText:text,replyKind:'text',userId:ctx.userId,phone:ctx.phone,instance:ctx.instance,remoteJid:ctx.remoteJid,messageId:ctx.messageId,reactionEmoji:'📋'}}];

const ctx=$input.first().json;const r=ctx.report||{};const period=r.period||'this_month';const today=new Date();const fmt=d=>d.toISOString().slice(0,10);let s,e;
if(period==='custom'&&r.start_date_iso&&r.end_date_iso){s=r.start_date_iso;e=r.end_date_iso;}
else if(period==='last_month'){const d=new Date(today.getFullYear(),today.getMonth()-1,1);s=fmt(d);e=fmt(new Date(today.getFullYear(),today.getMonth(),0));}
else if(period==='this_year'){s=`${today.getFullYear()}-01-01`;e=fmt(today);}
else if(period==='all'){s='2000-01-01';e=fmt(today);}
else{s=fmt(new Date(today.getFullYear(),today.getMonth(),1));e=fmt(today);}
return [{json:{...ctx,startDate:s,endDate:e}}];

