if(!items.length||!items[0].json.name){return [{json:{replyText:'📭 No tenés categorías cargadas todavía.',replyKind:'text',userId:ctx.userId,phone:ctx.phone,instance:ctx.instance,remoteJid:ctx.remoteJid,messageId:ctx.messageId,reactionEmoji:'📋'}}];}
